app = Flask(__name__)
ALGORITHMS = ["HS256", "RS256"]

def get_algorithm():
    return ALGORITHMS[0]  # Default to HS256

@app.route("/verify_token", methods=["POST"])
def verify_token():
    token = request.json.get("token")
    if not token:
        return jsonify({"error": "Token not provided"}), 400

    try:
        payload = verify_and_get_payload(token, get_algorithm())
        return jsonify(payload), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 401

def verify_and_get_payload(token, algorithm):
    try:
        payload = decode(token, algorithms=[algorithm])
    except jwt.ExpiredSignatureError:
        raise Exception("The token has expired.")
    except jwt.JWTError:
        raise Exception("Invalid token signature.")

    return payload

def create_token(payload, algorithm):
    return encode(payload, app.config["SECRET_KEY"], algorithm=algorithm)

